    46	uint32_t nfapi_calculate_checksum(uint8_t *buffer, uint16_t len) {
    47	  uint32_t chksum = 0;
    48	  // calcaulte upto the checksum
    49	  chksum = crc32(chksum, buffer, 8);
    50	  // skip the checksum
    51	  uint8_t zeros[4] = {0, 0, 0, 0};
    52	  chksum = crc32(chksum, zeros, 4);
    53	  // continu with the rest of the mesage
    54	  chksum = crc32(chksum, &buffer[NFAPI_P7_HEADER_LENGTH], len - NFAPI_P7_HEADER_LENGTH);
    55	  // return the inverse
    56	  return ~(chksum);
    57	}
