    59	int nfapi_p7_update_checksum(uint8_t *buffer, uint32_t len) {
    60	  uint32_t checksum = nfapi_calculate_checksum(buffer, len);
    61	  uint8_t *p_write = &buffer[8];
    62	  return (push32(checksum, &p_write, buffer + len) > 0 ? 0 : -1);
    63	}
